;// CONCATENATED MODULE: ./src/sync.ts

async function syncApp(playClient, githubClient, packageName, config) {
    let created = 0;
    let closed = 0;
    let filter = "";
    if (config.errorTypes === "CRASH") {
        filter = "errorIssueType = CRASH";
    }
    else if (config.errorTypes === "ANR") {
        filter = "errorIssueType = ANR";
    }
    const issues = await playClient.fetchErrorIssues(packageName, filter);
    info(`   Found ${issues.length} issues in Play Console for ${packageName}`);
    for (const issue of issues) {
        if (issue.affectedUsers < config.minAffectedUsers) {
            continue;
        }
        const dedupeLabel = `${config.labelPrefix}${issue.id}`;
        const existingIssue = await githubClient.findIssueByLabel(dedupeLabel);
        if (!existingIssue) {
            if (!issue.isResolved) {
                await githubClient.ensureLabel(dedupeLabel, "ededed");
                for (const label of config.extraLabels) {
                    await githubClient.ensureLabel(label);
                }
                await githubClient.createIssue(issue, [dedupeLabel, ...config.extraLabels]);
                created++;
                info(`     Created issue for ${issue.id}`);
            }
        }
        else {
            if (config.closeResolved && issue.isResolved && existingIssue.state === "open") {
                await githubClient.closeIssue(existingIssue.number, "This issue is marked as resolved in Google Play Console. Closing issue.");
                closed++;
                info(`     Closed issue ${existingIssue.number} for ${issue.id}`);
            }
        }
    }
    return { created, closed };
}

;// CONCATENATED MODULE: ./src/index.ts





async function run() {
    try {
        const config = parseConfig();
        const playClient = new PlayReportingClient(config.serviceAccountJson);
        let totalCreated = 0;
        let totalClosed = 0;
        for (const packageName of config.packageNames) {
            const repo = config.packageRepoMap[packageName] || null;
            const target = repo
                ? { owner: repo.split("/")[0], repo: repo.split("/")[1] }
                : config.defaultRepo;
            info(`🔍 Syncing ${packageName} -> ${target.owner}/${target.repo}`);
            const githubClient = new GitHubClient(config.githubToken, target.owner, target.repo);
            const result = await syncApp(playClient, githubClient, packageName, config);
            totalCreated += result.created;
            totalClosed += result.closed;
            info(`   ✅ ${result.created} created, ${result.closed} closed`);
        }
        setOutput("issues-created", totalCreated);
        setOutput("issues-closed", totalClosed);
    }
    catch (error) {
        setFailed(`Action failed: ${error.message}`);
    }
}
run();


